const result = JSON.parse($input.first().json.stdout || '{}');

// If below minimum, try to restart missing services
const actions = [];
const activePaths = result.ActivePaths || [];

if (!activePaths.includes('Tailscale')) {
  actions.push('Tailscale is DOWN - will attempt restart');
}
if (!activePaths.includes('RustDesk')) {
  actions.push('RustDesk is DOWN - will attempt restart');
}

return [{
  json: {
    ...result,
    actions: actions,
    needsRestart: actions.length > 0,
    needsAlert: result.BelowMinimum,
    timestamp: new Date().toISOString()
  }
}];

